class Solution {
      // Helper: Find row index of the largest element 
      // in the given column
      maxElement(arr, col) {
          let maxVal = Number.MIN_SAFE_INTEGER;
          let maxRow = -1;

          for (let row = 0; row < arr.length; row++) {
              if (arr[row][col] > maxVal) {
                  maxVal = arr[row][col];
                  maxRow = row;
              }
          }

          return maxRow;
      }

      // Main: Find a peak element in the 2D matrix 
      // using binary search on columns
      findPeakGrid(arr) {
          let n = arr.length;
          let m = arr[0].length;
          let low = 0;
          let high = m - 1;

          // Performing Binary Search
          while (low <= high) {
              let mid = Math.floor((low + high) / 2);
              let row = this.maxElement(arr, mid);

              // Finding the mid value and its neighbors
              let midVal = arr[row][mid];
              let leftVal = mid > 0 
                  ? arr[row][mid - 1] 
                  : Number.MIN_SAFE_INTEGER;
              let rightVal = mid < m - 1 
                  ? arr[row][mid + 1] 
                  : Number.MIN_SAFE_INTEGER;

              if (midVal > leftVal && midVal > rightVal) {
                  return [row, mid];
              } else if (leftVal > midVal) {
                  high = mid - 1;
              } else {
                  low = mid + 1;
              }
          }

          return [-1, -1];
      }
  }

  // Example usage
  const mat = [
      [4, 2, 5, 1, 4, 5],
      [2, 9, 3, 2, 3, 2],
      [1, 7, 6, 0, 1, 3],
      [3, 6, 2, 3, 7, 2]
  ];

  const sol = new Solution();
  const [peakRow, peakCol] = sol.findPeakGrid(mat);

  console.log(
    `The row of the peak element is ${peakRow} and ` + 
    `column of the peak element is ${peakCol}`
  );
